#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

my $q = CGI->new();
my $comment = $q->param('comment') || '';

# Sanitize the comment to allow only safe HTML formatting tags
# Remove any tags that are not in our whitelist
my %allowed_tags = map { $_ => 1 } qw(b i u em strong p br ul ol li a blockquote code pre);

# Process the comment to strip dangerous tags and attributes
$comment = sanitize_html($comment);

print "Content-type: text/html\n\n";
print "<div>$comment</div>";

sub sanitize_html {
    my ($text) = @_;

    # Remove script tags and their contents entirely
    $text =~ s/<script[^>]*>.*?<\/script>//gsi;
    $text =~ s/<style[^>]*>.*?<\/style>//gsi;
    $text =~ s/<iframe[^>]*>.*?<\/iframe>//gsi;
    $text =~ s/<object[^>]*>.*?<\/object>//gsi;
    $text =~ s/<embed[^>]*>.*?<\/embed>//gsi;
    $text =~ s/<form[^>]*>.*?<\/form>//gsi;

    # Remove event handler attributes (onload, onclick, onerror, etc.)
    $text =~ s/\bon\w+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]*)//gsi;

    # Remove javascript: and data: URIs in attributes
    $text =~ s/(href|src|action)\s*=\s*["']?\s*javascript:[^"'>]*["']?//gsi;
    $text =~ s/(href|src|action)\s*=\s*["']?\s*data:[^"'>]*["']?//gsi;
    $text =~ s/(href|src|action)\s*=\s*["']?\s*vbscript:[^"'>]*["']?//gsi;

    # Filter tags: only allow whitelisted tags
    $text =~ s/<(\/?)(\w+)([^>]*)>/
        my $slash = $1;
        my $tag = lc($2);
        my $attrs = $3;
        if ($allowed_tags{$tag}) {
            # For allowed tags, only permit safe attributes
            my $safe_attrs = sanitize_attributes($tag, $attrs);
            "<$slash$tag$safe_attrs>"
        } else {
            # Encode the disallowed tag so it renders as text
            "&lt;$slash$tag$attrs&gt;"
        }
    /gesi;

    return $text;
}

sub sanitize_attributes {
    my ($tag, $attrs) = @_;

    # Only allow specific safe attributes per tag
    my %safe_attrs = (
        'a'          => { 'href' => 1, 'title' => 1 },
        'blockquote' => { 'cite' => 1 },
    );

    return '' unless $attrs && $safe_attrs{$tag};

    my $result = '';
    while ($attrs =~ /(\w+)\s*=\s*(?:"([^"]*)"|'([^']*)'|(\S+))/g) {
        my $attr_name = lc($1);
        my $attr_val = defined($2) ? $2 : defined($3) ? $3 : $4;

        next unless $safe_attrs{$tag}{$attr_name};

        # Block dangerous URI schemes
        if ($attr_name eq 'href' || $attr_name eq 'cite') {
            next if $attr_val =~ /^\s*(javascript|data|vbscript)\s*:/i;
        }

        # Encode any embedded quotes
        $attr_val =~ s/"/&quot;/g;

        $result .= " $attr_name=\"$attr_val\"";
    }

    # For anchor tags, add rel="noopener noreferrer" for safety
    if ($tag eq 'a' && $result) {
        $result .= ' rel="noopener noreferrer"';
    }

    return $result;
}